import{_ as a,o,c as r,ag as i}from"./chunks/framework.OsDJF_Ea.js";const g=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"about/changelog.md","filePath":"about/changelog.md"}'),t={name:"about/changelog.md"};function n(s,e,l,d,c,h){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>What&#39;s actually shipped — pulled from the commit log, not marketing.</p><p>Format: <a href="https://keepachangelog.com/" target="_blank" rel="noreferrer">Keep a Changelog</a>. Versioning: <a href="https://semver.org/" target="_blank" rel="noreferrer">SemVer</a>.</p><h2 id="unreleased" tabindex="-1">Unreleased <a class="header-anchor" href="#unreleased" aria-label="Permalink to &quot;Unreleased&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Docs site hosted as a subpath of the main app: <a href="https://insposearch.org/docs/" target="_blank" rel="noreferrer">insposearch.org/docs/</a>. VitePress build output lives in <code>insposearch/docs/</code> and ships with the Pages deploy — no separate Pages project</li><li>In-page contact form on the institutions page (FormSubmit.co-backed, no backend, honeypot-protected)</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>View Docs</code> CTA and in-app <code>docs</code> link now point to <code>/docs/</code> instead of the decommissioned <code>insposearch-docs.pages.dev</code></li></ul><hr><h2 id="_1-1-0-—-2026-04-21-current" tabindex="-1">1.1.0 — 2026-04-21 (current) <a class="header-anchor" href="#_1-1-0-—-2026-04-21-current" aria-label="Permalink to &quot;1.1.0 — 2026-04-21 (current)&quot;">​</a></h2><p>Focus: stop the &quot;infinite scroll runs out at page 2&quot; problem, make exact mode genuinely exact, and put a real default AI provider in place so analysis works without BYOK.</p><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Workers AI as default vision provider</strong> — LLaVA 1.5 runs on Cloudflare&#39;s edge; analyse now works with zero keys configured. BYOK (Gemini / Claude / OpenAI / Ollama) still overrides when set</li><li><strong>Opt-in community metadata layer</strong> — users can contribute enrichment tags via the <code>/contribute</code> endpoint; data is reviewed before entering the shared corpus</li><li><strong>3-lane load-more dispatcher</strong> — Lane A (fresh pages), Lane B (query variations), Lane C (pool widening). Infinite scroll now keeps producing distinct results past page 5</li><li><strong>RRF fusion + MMR diversification</strong> on the unified result stream — reduces near-duplicates across sources, surfaces visually varied results first</li><li><strong>Deep-link URL state</strong> — query, mode, and source selection survive reload and are shareable</li><li><strong>Datamuse qualifier pool</strong> for Lane B rotation in exact mode — expands queries with linguistically related terms instead of synonyms that drift off-intent</li><li><strong>Paginated adapter coverage expanded</strong> from 17 to 29 sources — more sources participate in load-more instead of stalling after page 1</li><li><strong>Race-safe nightly fetch</strong> for CORS-blocked sources (GitHub Actions with rebase-and-retry push logic)</li><li><strong>Diacritic regression tests</strong> for Van Gogh / Dürer / Matisse-class queries across Met, Rijks, Europeana</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Worker endpoints expanded</strong> to 10: <code>/search</code>, <code>/sources</code>, <code>/random</code>, <code>/health</code>, <code>/proxy</code>, <code>/semantic</code>, <code>/caption</code>, <code>/tags</code>, <code>/contribute</code>, <code>/board</code></li><li><strong>Fetch concurrency</strong> raised to 40; slow-source timeout ceiling raised to 12s</li><li><strong>Source health</strong> scoped per query intent, reset on each new query — a source that misses on <code>vermeer</code> is no longer penalised when you search <code>brutalism</code></li><li><strong>Intent penalty relaxed</strong> for weakly-classified queries so ambiguous terms don&#39;t over-filter</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Analyse button now acts on the panel-previewed item, not only the grid-selected one</li><li>Analyse no longer early-returns when BYOK is empty — Workers AI default path fires as intended</li><li>Met / Europeana / Rijks exact-mode matching across diacritic variants (<code>van gogh</code> ↔ <code>Van Gogh</code> ↔ <code>van Gog</code>)</li><li>Load-more actually yields new items (was silently returning duplicates)</li><li>Deep-link URL updates on every search (module binding reassignment bug)</li><li>Met CORS proxy, Smithsonian 429 handling, KHM mixed content, favicon 504 flood, 7 dead source APIs disabled, 14 manifest validation errors</li><li>Single-word category queries no longer collapse to empty results</li><li>Image proxy URL corrected to the official subdomain</li></ul><hr><h2 id="_1-0-0-—-2025-10-01-—-initial-public-release" tabindex="-1">1.0.0 — 2025-10-01 — Initial public release <a class="header-anchor" href="#_1-0-0-—-2025-10-01-—-initial-public-release" aria-label="Permalink to &quot;1.0.0 — 2025-10-01 — Initial public release&quot;">​</a></h2><ul><li>Unified client-side search across 2,400+ cultural heritage sources (static registry + Europeana / DPLA dynamic provider discovery)</li><li>Search modes: exact (precision) and explore (recall)</li><li>Infinite-scroll result grid with quality gates and preload-then-append rendering</li><li>Detail view with metadata, arrow-key navigation, colour palette extraction</li><li>Board view (localStorage + shared-via-KV boards with 30-day TTL)</li><li>Deep zoom via OpenSeadragon for IIIF-compatible sources</li><li>3D constellation view for visual similarity exploration</li><li>Interpret: cross-reference any image across all sources</li><li>101 interface languages (6 hand-translated + 95 generated)</li><li>Keys panel for optional provider authentication (stored in localStorage, sent only to the respective provider)</li><li>Dark-first monospace UI (Cormorant Garamond + DM Mono), AGPL-3.0</li></ul><hr><h2 id="reading-the-commit-log-directly" tabindex="-1">Reading the commit log directly <a class="header-anchor" href="#reading-the-commit-log-directly" aria-label="Permalink to &quot;Reading the commit log directly&quot;">​</a></h2><p>For anything between releases: <a href="https://github.com/GI-Synth/InspoSearch/commits/main" target="_blank" rel="noreferrer">github.com/GI-Synth/InspoSearch/commits/main</a>.</p>',23)])])}const p=a(t,[["render",n]]);export{g as __pageData,p as default};
